import React, { useState } from "react";
import { Camera, CameraResultType, CameraSource } from "@capacitor/camera";

function App() {
  const [photo, setPhoto] = useState(null);
  const [uploading, setUploading] = useState(false);

  // 사진 촬영
  const takePhoto = async () => {
    try {
      const image = await Camera.getPhoto({
        quality: 90,
        allowEditing: true,
        resultType: CameraResultType.Uri,
        source: CameraSource.Camera,
        saveToGallery: true,
      });
      setPhoto(image.webPath);
    } catch (err) {
      console.error("카메라 오류:", err);
    }
  };

  // 사진 삭제
  const deletePhoto = () => {
    setPhoto(null);
  };

  // 서버 전송 (데모)
  const uploadPhoto = async () => {
    if (!photo) return;
    setUploading(true);

    // 실제 전송 로직이 들어갈 자리 (setTimeout으로 전송 중인 척!)
    setTimeout(() => {
      setUploading(false);
      alert("서버 전송이 완료되었습니다!");
      setPhoto(null);
    }, 1500);
  };

  // 버튼 호버 스타일을 위한 훅
  const useHover = () => {
    const [hover, setHover] = useState(false);
    const onMouseEnter = () => setHover(true);
    const onMouseLeave = () => setHover(false);
    return [hover, { onMouseEnter, onMouseLeave }];
  };

  const [mainBtnHover, mainBtnHoverEvents] = useHover();
  const [uploadBtnHover, uploadBtnHoverEvents] = useHover();

  return (
    <div style={wrapperStyle}>
      {/* 상단 바 - 앱 이름과 카메라 아이콘 추가 */}
      <header style={headerStyle}>
        <div style={headerContentStyle}>
          <span style={headerIconStyle}>📸</span>
          <h1 style={headerTitleStyle}>Capacitor Camera</h1>
        </div>
      </header>

      <main style={mainStyle}>
        {/* 사진 표시 영역 - 스타일 개선 */}
        <div style={photoCardStyle}>
          {photo ? (
            <>
              <img src={photo} alt="Preview" style={imageStyle} />
              <button onClick={deletePhoto} style={closeButtonStyle}>
                ✕
              </button>
            </>
          ) : (
            <div style={placeholderStyle} onClick={takePhoto}>
              <div style={placeholderIconStyle}>📷</div>
              <p style={placeholderTextStyle}>클릭하여 사진 촬영</p>
              <p style={placeholderSubTextStyle}>
                사진을 업로드하여 결과를 확인하세요
              </p>
            </div>
          )}
        </div>

        {/* 상태 안내 메시지 - 스타일 개선 */}
        <div style={statusStyle}>
          {photo
            ? "서버로 전송할 준비가 되었습니다."
            : "업로드할 사진을 촬영해주세요."}
        </div>
      </main>

      {/* 하단 버튼 영역 - 스타일 및 애니메이션 효과 추가 */}
      <footer style={footerStyle}>
        {!photo ? (
          <button
            onClick={takePhoto}
            style={{
              ...mainButtonStyle,
              ...(mainBtnHover ? mainButtonStyleHover : {}),
            }}
            {...mainBtnHoverEvents}
          >
            사진 찍기
          </button>
        ) : (
          <button
            onClick={uploadPhoto}
            style={{
              ...mainButtonStyle,
              backgroundColor: "#28a745",
              ...(uploadBtnHover
                ? { backgroundColor: "#218838", transform: "scale(1.02)" }
                : {}),
              ...(uploading ? { opacity: 0.7 } : {}),
            }}
            disabled={uploading}
            {...uploadBtnHoverEvents}
          >
            {uploading ? "전송 중..." : "서버로 전송하기"}
          </button>
        )}
      </footer>
    </div>
  );
}

// --- 더 예쁘고 앱다운 스타일 ---

const wrapperStyle = {
  backgroundColor: "#f0f2f5", // 조금 더 따뜻한 회색 배경
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  fontFamily:
    "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif", // 시스템 폰트 사용
};

const headerStyle = {
  height: "70px", // 조금 더 높게
  backgroundColor: "#fff",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  borderBottom: "1px solid #eee",
  boxShadow: "0 2px 10px rgba(0,0,0,0.05)", // 상단 바에 부드러운 그림자
};

const headerContentStyle = {
  display: "flex",
  alignItems: "center",
  gap: "10px",
};

const headerIconStyle = {
  fontSize: "28px",
};

const headerTitleStyle = {
  fontSize: "22px",
  margin: 0,
  fontWeight: "bold",
  color: "#333",
};

const mainStyle = {
  flex: 1,
  padding: "30px 20px", // 패딩 증가
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
};

const photoCardStyle = {
  width: "100%",
  maxWidth: "380px", // 최대 너비 증가
  aspectRatio: "3/4",
  backgroundColor: "#fff",
  borderRadius: "20px", // 모서리 더 둥글게
  boxShadow: "0 8px 20px rgba(0,0,0,0.1)", // 입체감 있는 그림자
  position: "relative",
  overflow: "hidden",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  cursor: "pointer",
  transition: "box-shadow 0.3s ease", // 그림자 애니메이션
  ":hover": {
    // 인라인 스타일로 호버 효과 구현의 한계로 인해 주석 처리
    // boxShadow: "0 10px 25px rgba(0,0,0,0.15)",
  },
};

const imageStyle = {
  width: "100%",
  height: "100%",
  objectFit: "cover",
};

const placeholderStyle = {
  textAlign: "center",
  padding: "40px",
  backgroundColor: "#f8f9fa", // 플레이스홀더 배경색
  borderRadius: "15px",
};

const placeholderIconStyle = {
  fontSize: "60px",
  color: "#ced4da",
  marginBottom: "15px",
};

const placeholderTextStyle = {
  margin: "0 0 5px 0",
  color: "#495057",
  fontSize: "18px",
  fontWeight: "bold",
};

const placeholderSubTextStyle = {
  margin: 0,
  color: "#868e96",
  fontSize: "14px",
};

const closeButtonStyle = {
  position: "absolute",
  top: "15px",
  right: "15px",
  width: "35px", // 조금 더 크게
  height: "35px",
  borderRadius: "50%",
  backgroundColor: "rgba(0,0,0,0.6)", // 배경 투명도 조정
  color: "#fff",
  border: "none",
  cursor: "pointer",
  fontSize: "18px",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  boxShadow: "0 2px 5px rgba(0,0,0,0.2)",
};

const statusStyle = {
  marginTop: "25px", // 간격 증가
  color: "#495057",
  fontSize: "15px",
  fontWeight: "500",
};

const footerStyle = {
  padding: "25px 20px", // 패딩 증가
  backgroundColor: "#fff",
  borderTop: "1px solid #eee",
  boxShadow: "0 -2px 10px rgba(0,0,0,0.03)", // 하단 버튼 영역에 그림자
};

const mainButtonStyle = {
  width: "100%",
  padding: "18px", // 조금 더 도톰하게
  borderRadius: "15px", // 모서리 더 둥글게
  border: "none",
  backgroundColor: "#007bff",
  color: "#fff",
  fontSize: "18px", // 글자 크기 증가
  fontWeight: "bold",
  cursor: "pointer",
  transition: "all 0.2s ease-in-out", // 애니메이션 효과 추가
  boxShadow: "0 4px 6px rgba(0,123,255,0.3)", // 버튼에 그림자 추가
};

const mainButtonStyleHover = {
  backgroundColor: "#0056b3",
  transform: "scale(1.02)", // 살짝 커지는 효과
};

export default App;
